@namespace Lumeo

@if (Animation == SkeletonAnimation.Wave)
{
    <style>
        @@keyframes skeleton-wave {
            0% { background-position: -200% 0; }
            100% { background-position: 200% 0; }
        }
    </style>
    <div class="@($"rounded-md bg-gradient-to-r from-primary/10 via-primary/5 to-primary/10 bg-[length:200%_100%] {Class}".Trim())"
         style="animation: skeleton-wave 1.5s ease-in-out infinite"
         @attributes="AdditionalAttributes"></div>
}
else
{
    <div class="@($"{AnimationClass} rounded-md bg-primary/10 {Class}".Trim())" @attributes="AdditionalAttributes"></div>
}

@code {
    [Parameter] public SkeletonAnimation Animation { get; set; } = SkeletonAnimation.Pulse;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string AnimationClass => Animation switch
    {
        SkeletonAnimation.Pulse => "animate-pulse",
        SkeletonAnimation.None => "",
        _ => "animate-pulse"
    };

    public enum SkeletonAnimation { Pulse, Wave, None }
}

@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    <Skeleton Animation="Animation" Class="h-32 w-full rounded-t-lg" />
    <div class="p-4 space-y-3">
        <Skeleton Animation="Animation" Class="h-5 w-3/4" />
        <Skeleton Animation="Animation" Class="h-4 w-full" />
        <Skeleton Animation="Animation" Class="h-4 w-1/2" />
    </div>
</div>

@code {
    [Parameter] public Skeleton.SkeletonAnimation Animation { get; set; } = Skeleton.SkeletonAnimation.Pulse;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"rounded-lg border border-border overflow-hidden {Class}".Trim();
}

@namespace Lumeo

@if (Animation == Skeleton.SkeletonAnimation.Wave)
{
    <style>
        @@keyframes skeleton-wave {
            0% { background-position: -200% 0; }
            100% { background-position: 200% 0; }
        }
    </style>
    <div class="@($"rounded-full bg-gradient-to-r from-primary/10 via-primary/5 to-primary/10 bg-[length:200%_100%] h-10 w-10 {Class}".Trim())"
         style="animation: skeleton-wave 1.5s ease-in-out infinite"
         @attributes="AdditionalAttributes"></div>
}
else
{
    <div class="@CssClass" @attributes="AdditionalAttributes"></div>
}

@code {
    [Parameter] public Skeleton.SkeletonAnimation Animation { get; set; } = Skeleton.SkeletonAnimation.Pulse;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string AnimationClass => Animation switch
    {
        Skeleton.SkeletonAnimation.Pulse => "animate-pulse",
        Skeleton.SkeletonAnimation.None => "",
        _ => "animate-pulse"
    };

    private string CssClass => string.Join(" ", new[] { AnimationClass, "rounded-full bg-primary/10 h-10 w-10", Class }.Where(s => !string.IsNullOrWhiteSpace(s)));
}

@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    @for (var i = 0; i < Lines; i++)
    {
        <Skeleton Animation="Animation" Class="@($"h-4 {(i == Lines - 1 ? "w-3/4" : "w-full")}")" />
    }
</div>

@code {
    [Parameter] public int Lines { get; set; } = 3;
    [Parameter] public Skeleton.SkeletonAnimation Animation { get; set; } = Skeleton.SkeletonAnimation.Pulse;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"space-y-2 {Class}".Trim();
}
